-- Insert 39 new explosiveness exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Falling Start Sprint', 'falling-start-sprint', 'Falling Start Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Falling Start Sprint trains body-angle trust and violent first-step acceleration from a falling lean. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: first-step starts. Coach Falling Start Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'first_step_starts', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","calves","achilles_tendon","foot_intrinsics"],"breathing_demand":"rhythmic_braced","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Falling Start Sprint is an Output-phase explosiveness drill for body-angle trust and violent first-step acceleration from a falling lean. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Mark a short acceleration lane with cones.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Falling Start Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('2-Point Acceleration Start', '2-point-acceleration-start', '2-Point Acceleration Start is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, '2-Point Acceleration Start trains explosive acceleration from a simple athletic stance. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: first-step starts. Coach 2-Point Acceleration Start as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'first_step_starts', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","quadriceps","calves","achilles_tendon"],"breathing_demand":"rhythmic_braced","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"2-Point Acceleration Start is an Output-phase explosiveness drill for explosive acceleration from a simple athletic stance. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Mark a short acceleration lane with cones.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","2-Point Acceleration Start: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('Half-Kneeling Sprint Start', 'half-kneeling-sprint-start', 'Half-Kneeling Sprint Start is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Half-Kneeling Sprint Start trains start power from a low, asymmetrical position. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: first-step starts. Coach Half-Kneeling Sprint Start as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'first_step_starts', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","quadriceps","calves","achilles_tendon"],"breathing_demand":"rhythmic_braced","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Half-Kneeling Sprint Start is an Output-phase explosiveness drill for start power from a low, asymmetrical position. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Mark a short acceleration lane with cones.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Half-Kneeling Sprint Start: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('Push-Up Start Sprint', 'push-up-start-sprint', 'Push-Up Start Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Push-Up Start Sprint trains ground-to-sprint explosiveness with upper-body pop and fast hip recovery. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: ground-to-sprint starts. Coach Push-Up Start Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'ground_to_sprint_starts', '{"primary_joint_actions":["shoulder_horizontal_flexion","elbow_extension","trunk_bracing","hip_extension","knee_drive","ankle_stiffness"],"primary_tissues":["pectorals","deltoids","serratus_anterior","forearms","abdominals","obliques"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Push-Up Start Sprint is an Output-phase explosiveness drill for ground-to-sprint explosiveness with upper-body pop and fast hip recovery. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Mark a short acceleration lane with cones.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Push-Up Start Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('Prone Pop-Up to Sprint', 'prone-pop-up-to-sprint', 'Prone Pop-Up to Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Prone Pop-Up to Sprint trains rapid get-up mechanics into a hard first three steps. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: ground-to-sprint starts. Coach Prone Pop-Up to Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'ground_to_sprint_starts', '{"primary_joint_actions":["shoulder_horizontal_flexion","elbow_extension","trunk_bracing","hip_extension","knee_drive","ankle_stiffness"],"primary_tissues":["pectorals","deltoids","serratus_anterior","abdominals","obliques","glutes"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Prone Pop-Up to Sprint is an Output-phase explosiveness drill for rapid get-up mechanics into a hard first three steps. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Mark a short acceleration lane with cones.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Prone Pop-Up to Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('Wall-Drive Switch to Sprint', 'wall-drive-switch-to-sprint', 'Wall-Drive Switch to Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Wall-Drive Switch to Sprint trains switching acceleration rhythm immediately into projection. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: acceleration transfer. Coach Wall-Drive Switch to Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'acceleration_transfer', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","calves","achilles_tendon","foot_intrinsics"],"breathing_demand":"rhythmic_braced","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Wall-Drive Switch to Sprint is an Output-phase explosiveness drill for switching acceleration rhythm immediately into projection. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set the athlete at a wall with hands at shoulder height and body in a straight acceleration lean.","Start fresh after warm-up and movement prep.","Confirm the athlete understands the start position, finish distance, and full-reset requirement."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Wall-Drive Switch to Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
  ('Light Sled Sprint Push', 'light-sled-sprint-push', 'Light Sled Sprint Push is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Light Sled Sprint Push trains resisted acceleration with maximal intent and low enough load to stay fast. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Acceleration Start Speed. Slot: resisted acceleration. Coach Light Sled Sprint Push as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'acceleration_start_speed', 'resisted_acceleration', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","shoulder_horizontal_flexion","elbow_extension","trunk_bracing"],"primary_tissues":["glutes","hamstrings","hip_flexors","quadriceps","calves","achilles_tendon"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Light Sled Sprint Push is an Output-phase explosiveness drill for resisted acceleration with maximal intent and low enough load to stay fast. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a light sled load that allows fast acceleration mechanics, not a slow grind.","Mark a short lane of 5-15 yards with cones.","Confirm clear space and a stable surface before each effort."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Light Sled Sprint Push: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Loading the sled too heavy and changing the drill into a slow strength push."]}'::jsonb),
  ('Partner Chase First-Step Sprint', 'partner-chase-first-step-sprint', 'Partner Chase First-Step Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Partner Chase First-Step Sprint trains live first-step acceleration under a simple chase stimulus. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Reactive Agility / Tumbling Output. Slot: reactive first step. Coach Partner Chase First-Step Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Acceleration / First-Step Output', 'output', 'reactive_agility_tumbling_output', 'reactive_first_step', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","calves","achilles_tendon","foot_intrinsics"],"breathing_demand":"rhythmic_braced","balance_demand":"reactive_dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Partner Chase First-Step Sprint is an Output-phase explosiveness drill for live first-step acceleration under a simple chase stimulus. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a short reaction lane with cones and one clear start line.","Define the cue, finish point, and reset rule before the set starts.","Keep the stimulus simple enough that the athlete can react explosively without guessing or drifting."],"execution_steps":["Hold the start position until the live cue appears.","React with the first purposeful step rather than rocking or false stepping.","Accelerate, bound, or redirect through the assigned finish, then walk back and fully reset."],"coach_cues":["See it, go.","No guessing step.","Explode after the cue.","Reset fully.","Partner Chase First-Step Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Making the cue so complex that the athlete hesitates instead of reacting explosively."]}'::jsonb),
  ('Line Hops', 'line-hops', 'Line Hops is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 12, 12, 60, 75, 'Line Hops trains low-amplitude rapid contacts over a line. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Elastic Stiffness Plyometric Rudiments. Slot: elastic contacts. Coach Line Hops as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Elastic Foot-Ankle Power', 'output', 'elastic_stiffness_plyometric_rudiments', 'elastic_contacts', '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantar_flexion","hip_knee_ankle_absorption","trunk_bracing"],"primary_tissues":["foot_intrinsics","calves","achilles_tendon","quadriceps","hamstrings","glutes"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb, '{"movement_description":"Line Hops is an Output-phase explosiveness drill for low-amplitude rapid contacts over a line. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Clear the landing area and use a stable, non-slip surface.","Start with the lowest amplitude version that allows quiet contacts and clean alignment.","Place cones, box, line, or target only as needed for the variation."],"execution_steps":["Load only as much as needed to create a fast takeoff or contact.","Explode through the floor with the intended direction and posture.","Land, rebound, or stick according to the drill; end the rep the moment alignment or contact quality drops."],"coach_cues":["Hot floor.","Springy and quiet.","Tall hips.","Stop before contacts get heavy.","Line Hops: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."]}'::jsonb),
