  ('Reaction Ball Drop Sprint', 'reaction-ball-drop-sprint', 'Reaction Ball Drop Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Reaction Ball Drop Sprint trains visual reaction into explosive first-step acceleration. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Reactive Agility / Tumbling Output. Slot: reactive first step. Coach Reaction Ball Drop Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Reactive Explosiveness', 'output', 'reactive_agility_tumbling_output', 'reactive_first_step', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","calves","achilles_tendon","foot_intrinsics"],"breathing_demand":"rhythmic_braced","balance_demand":"reactive_dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Reaction Ball Drop Sprint is an Output-phase explosiveness drill for visual reaction into explosive first-step acceleration. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a short reaction lane with cones and one clear start line.","Define the cue, finish point, and reset rule before the set starts.","Keep the stimulus simple enough that the athlete can react explosively without guessing or drifting."],"execution_steps":["Hold the start position until the live cue appears.","React with the first purposeful step rather than rocking or false stepping.","Accelerate, bound, or redirect through the assigned finish, then walk back and fully reset."],"coach_cues":["See it, go.","No guessing step.","Explode after the cue.","Reset fully.","Reaction Ball Drop Sprint: quality beats quantity."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Making the cue so complex that the athlete hesitates instead of reacting explosively."]}'::jsonb),
  ('Mirror First-Step Chase', 'mirror-first-step-chase', 'Mirror First-Step Chase is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.', 'INTERMEDIATE', 8, 3, 3, 8, 90, 105, 'Mirror First-Step Chase trains live opponent read into a first-step chase or escape. Use it when the session needs fresh explosiveness rather than loaded strength volume.', 'Primary subrole: Reactive Agility / Tumbling Output. Slot: reactive first step. Coach Mirror First-Step Chase as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.', 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.', 'Reactive Explosiveness', 'output', 'reactive_agility_tumbling_output', 'reactive_first_step', '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","quadriceps","calves","achilles_tendon"],"breathing_demand":"rhythmic_braced","balance_demand":"reactive_dynamic","coordination_demand":"high","impact_level":2}'::jsonb, '{"movement_description":"Mirror First-Step Chase is an Output-phase explosiveness drill for live opponent read into a first-step chase or escape. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a short reaction lane with cones and one clear start line.","Define the cue, finish point, and reset rule before the set starts.","Keep the stimulus simple enough that the athlete can react explosively without guessing or drifting."],"execution_steps":["Hold the start position unt