  ('half-kneeling-sprint-start', 'output', 'first_step_starts', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('push-up-start-sprint', 'output', 'ground_to_sprint_starts', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('prone-pop-up-to-sprint', 'output', 'ground_to_sprint_starts', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('wall-drive-switch-to-sprint', 'output', 'acceleration_transfer', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('light-sled-sprint-push', 'output', 'resisted_acceleration', 5, TRUE, 5, 4, 3, 2, 'high'),
