  ('line-hops', 'output', 'elastic_contacts', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('jump-rope-power-singles', 'output', 'elastic_contacts', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('single-leg-pogo-jumps', 'output', 'single_leg_elastic_contacts', 5, TRUE, 5, 5, 4, 4, 'high'),
  ('a-skip-rhythm-punch', 'output', 'sprint_stiffness_rudiments', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('pogo-to-10-yard-sprint', 'output', 'sprint_transfer', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('low-hurdle-quick-hop', 'output', 'reactive_plyometrics', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('tuck-jump', 'output', 'vertical_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('split-squat-jump', 'output', 'split_stance_power', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('lunge-switch-jump', 'output', 'split_stance_reactive_power', 5, TRUE, 5, 5, 4, 4, 'high'),
  ('sprinter-step-up-jump', 'output', 'step_up_jump_power', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('seated-box-jump', 'output', 'dead_start_jump_power', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('depth-jump-to-vertical-jump', 'output', 'reactive_plyometrics', 5, TRUE, 5, 5, 4, 4, 'high'),
  ('rotational-bound-to-stick', 'output', 'rotational_power', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('180-degree-jump-to-stick', 'output', 'rotational_power', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('crossover-bound', 'output', 'lateral_power', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('curved-sprint-bound', 'output', 'curved_sprint_power', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('deceleration-re-acceleration-sprint', 'output', 'decel_reaccel_power', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('5-10-5-explosive-plant-drill', 'output', 'cod_power', 5, TRUE, 5, 5, 4, 3, 'high'),
  ('medicine-ball-scoop-toss', 'output', 'medicine_ball_power', 5, TRUE, 5, 4, 3, 1, 'high'),
  ('medicine-ball-rotational-throw', 'output', 'rotational_throw_power', 5, TRUE, 5, 4, 3, 1, 'high'),
  ('medicine-ball-side-toss-with-step', 'output', 'rotational_throw_power', 5, TRUE, 5, 4, 3, 1, 'high'),
  ('kneeling-medicine-ball-chest-pass', 'output', 'medicine_ball_power', 5, TRUE, 5, 4, 3, 0, 'high'),
  ('drop-catch-medicine-ball-chest-pass', 'output', 'reactive_throw_power', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('plyo-push-up', 'output', 'upper_body_power', 5, TRUE, 5, 4, 3, 2, 'high'),
  ('reaction-ball-drop-sprint', 'output', 'reactive_first_step', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('mirror-first-step-chase', 'output', 'reactive_first_step', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('tennis-ball-split-step-sprint', 'output', 'reactive_first_step', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('partner-bump-and-go-start', 'output', 'reactive_contact_start', 5, TRUE, 5, 5, 4, 3, 'high'),
  ('tag-and-go-acceleration', 'output', 'reactive_first_step', 5, TRUE, 5, 4, 4, 2, 'high'),
  ('reactive-lateral-bound-callout', 'output', 'reactive_lateral_power', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('auditory-start-sprint', 'output', 'reactive_first_step', 5, TRUE, 5, 4, 4, 2, 'high')
) AS m(slug, phase_key, slot, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

