INSERT INTO coaching.exercise_safety_profile (
  exercise_id, risk_level, impact_level, requires_spotting, requires_coach_supervision,
  readiness_checks, contraindications, common_substitutions
)
SELECT e.id, COALESCE(m.risk_level, 2), COALESCE(m.impact_level, 2), COALESCE(m.requires_spotting, FALSE),
  COALESCE(m.requires_coach_supervision, 'optional'),
  COALESCE(m.readiness_checks, ARRAY[]::text[]),
  COALESCE(m.contraindications, ARRAY[]::text[]),
  COALESCE(m.common_substitutions, ARRAY[]::text[])
FROM (VALUES
  ('falling-start-sprint', 2, 2, FALSE, 'optional', ARRAY['Pain-free dynamic warm-up and movement prep completed.', 'Athlete can demonstrate the lower-level version with control.', 'Coach can provide enough rest and space for high-quality output.']::text[], ARRAY['Pain with the selected takeoff, landing, throw, sprint, or brace position.', 'Uncontrolled joint alignment at a lower progression.', 'Athlete is too fatigued to keep reps crisp.']::text[], ARRAY['Marching wall drive', 'A-march', 'Low-intensity build-up sprint']::text[]),
